import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useRef,
  useState,
} from 'react';
import { createPortal } from 'react-dom';
import { overlayHub, type OverlayHub } from '@arvo/core';
import { OverlayContext } from '../../providers/OverlayContext';

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export type ArvoToastType = 'negative' | 'warning' | 'info' | 'positive' | 'block' | 'neutral';
export type ArvoToastPosition = 'top-right' | 'top-left' | 'bottom-right' | 'bottom-left';
export type ArvoToastCloseReason = 'click' | 'escape' | 'fade' | 'programmatic';

export interface ArvoToastOptions {
  type?: ArvoToastType;
  title?: string | null;
  message: string;
  fadeAway?: boolean;
  timeout?: number;
  pauseOnHover?: boolean;
  icon?: string | null;
  link?: React.ReactNode;
  className?: string;
  onClose?: () => void;
  onMouseEnter?: () => void;
  onMouseLeave?: () => void;
}

export interface ArvoToastProviderProps {
  position?: ArvoToastPosition;
  children: React.ReactNode;
}

interface ToastEntry extends ArvoToastOptions {
  id: string;
}

interface ToastContextValue {
  show: (options: ArvoToastOptions) => string;
  close: (id: string) => void;
  closeAll: () => void;
}

// ---------------------------------------------------------------------------
// Context
// ---------------------------------------------------------------------------

const ToastContext = createContext<ToastContextValue | null>(null);

export function useToast(): ToastContextValue {
  const ctx = useContext(ToastContext);
  if (!ctx) {
    throw new Error('useToast must be used within an ArvoToastProvider');
  }
  return ctx;
}

// Error types that never auto-dismiss
const NO_AUTO_DISMISS: ReadonlySet<ArvoToastType> = new Set(['negative', 'block']);
const ALERT_ROLES: ReadonlySet<ArvoToastType> = new Set(['negative', 'block']);

let toastCounter = 0;

// ---------------------------------------------------------------------------
// ToastItem — internal component for a single toast
// ---------------------------------------------------------------------------

interface ToastItemProps {
  entry: ToastEntry;
  onRemove: (id: string, reason: ArvoToastCloseReason) => void;
}

function ToastItem({ entry, onRemove }: ToastItemProps) {
  const {
    id,
    type = 'info',
    title,
    message,
    fadeAway: fadeAwayProp = true,
    timeout = 5000,
    pauseOnHover = true,
    icon,
    link,
    className,
    onClose,
    onMouseEnter: onMouseEnterCb,
    onMouseLeave: onMouseLeaveCb,
  } = entry;

  const shouldFade = NO_AUTO_DISMISS.has(type) ? false : fadeAwayProp;
  const role = ALERT_ROLES.has(type) ? 'alert' : 'status';

  const elRef = useRef<HTMLDivElement>(null);
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const removedRef = useRef(false);

  const remove = useCallback((reason: ArvoToastCloseReason) => {
    if (removedRef.current) return;
    removedRef.current = true;
    onClose?.();
    onRemove(id, reason);
  }, [id, onClose, onRemove]);

  // Start fade-away timeout
  useEffect(() => {
    if (!shouldFade) return;
    timerRef.current = setTimeout(() => {
      const el = elRef.current;
      if (!el) { remove('fade'); return; }
      el.classList.add('is-fading');
      el.classList.remove('is-paused');
      const onEnd = () => {
        el.removeEventListener('transitionend', onEnd);
        remove('fade');
      };
      el.addEventListener('transitionend', onEnd);
    }, timeout);
    return () => {
      if (timerRef.current) clearTimeout(timerRef.current);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleMouseEnter = useCallback(() => {
    onMouseEnterCb?.();
    if (!shouldFade || !pauseOnHover) return;
    if (timerRef.current) { clearTimeout(timerRef.current); timerRef.current = null; }
    const el = elRef.current;
    if (el) {
      el.classList.add('is-paused');
      el.classList.remove('is-fading');
    }
  }, [shouldFade, pauseOnHover, onMouseEnterCb]);

  const handleMouseLeave = useCallback(() => {
    onMouseLeaveCb?.();
    if (!shouldFade || !pauseOnHover) return;
    const el = elRef.current;
    if (el) { el.classList.remove('is-paused'); }
    timerRef.current = setTimeout(() => {
      if (!elRef.current) { remove('fade'); return; }
      elRef.current.classList.add('is-fading');
      const onEnd = () => {
        elRef.current?.removeEventListener('transitionend', onEnd);
        remove('fade');
      };
      elRef.current.addEventListener('transitionend', onEnd);
    }, timeout);
  }, [shouldFade, pauseOnHover, timeout, remove, onMouseLeaveCb]);

  const handleCloseClick = useCallback(() => { remove('click'); }, [remove]);

  const handleKeyDown = useCallback((e: React.KeyboardEvent) => {
    if (e.key === 'Escape') {
      e.stopPropagation();
      remove('escape');
    }
  }, [remove]);

  const rootClasses = [
    'arvo-toast',
    `arvo-toast--${type}`,
    className,
  ].filter(Boolean).join(' ');

  const iconClasses = [
    'arvo-toast__ico',
    'o9con',
    icon ? `o9con-${icon}` : '',
  ].filter(Boolean).join(' ');

  return (
    <div
      ref={elRef}
      className={rootClasses}
      role={role}
      aria-atomic="true"
      onMouseEnter={handleMouseEnter}
      onMouseLeave={handleMouseLeave}
      onKeyDown={handleKeyDown}
    >
      <span className={iconClasses} aria-hidden="true" />
      <div className="arvo-toast__content">
        <div>
          {title && <p className="arvo-toast__title">{title}</p>}
          <p className="arvo-toast__msg">{message}</p>
        </div>
        {link && <div className="arvo-toast__link">{link}</div>}
      </div>
      <button
        className="arvo-toast__close"
        aria-label="Close notification"
        onClick={handleCloseClick}
        type="button"
      >
        <span className="o9con o9con-close" />
      </button>
    </div>
  );
}

// ---------------------------------------------------------------------------
// ArvoToastProvider
// ---------------------------------------------------------------------------

const OVERLAY_ID = 'arvo-toast-container';

function ArvoToastProvider({ position = 'top-right', children }: ArvoToastProviderProps) {
  const [toasts, setToasts] = useState<ToastEntry[]>([]);
  const containerRef = useRef<HTMLDivElement | null>(null);
  const registeredRef = useRef(false);

  // Use the provider's hub when available; fall back to module singleton.
  const hub: OverlayHub = useContext(OverlayContext) ?? overlayHub;

  // Lazily create container DOM element
  if (!containerRef.current && typeof document !== 'undefined') {
    const el = document.createElement('div');
    el.className = `arvo-toast-container arvo-toast-container--${position}`;
    el.setAttribute('role', 'region');
    el.setAttribute('aria-label', 'Notifications');
    containerRef.current = el;
  }

  // Mount container to body & register with overlay hub
  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;
    document.body.appendChild(container);

    hub.open({
      id: OVERLAY_ID,
      type: 'toast',
      element: container,
      priority: 0,
      config: { autoCloseOnOutsideClick: false },
    });
    registeredRef.current = true;

    return () => {
      if (registeredRef.current) {
        hub.close(OVERLAY_ID);
        registeredRef.current = false;
      }
      container.remove();
    };
  }, [hub]);

  // Update position class when prop changes
  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;
    container.className = `arvo-toast-container arvo-toast-container--${position}`;
  }, [position]);

  const show = useCallback((options: ArvoToastOptions): string => {
    const id = `arvo-toast-${++toastCounter}`;
    setToasts(prev => [{ ...options, id }, ...prev]);
    return id;
  }, []);

  const close = useCallback((id: string) => {
    setToasts(prev => prev.filter(t => t.id !== id));
  }, []);

  const closeAll = useCallback(() => {
    setToasts([]);
  }, []);

  const handleRemove = useCallback((id: string, reason: ArvoToastCloseReason) => {
    const container = containerRef.current;
    if (container) {
      container.dispatchEvent(new CustomEvent('toast:close', {
        bubbles: true,
        cancelable: false,
        detail: { id, reason },
      }));
    }
    setToasts(prev => prev.filter(t => t.id !== id));
  }, []);

  const contextValue: ToastContextValue = { show, close, closeAll };

  return (
    <ToastContext.Provider value={contextValue}>
      {children}
      {containerRef.current && createPortal(
        toasts.map(entry => (
          <ToastItem
            key={entry.id}
            entry={entry}
            onRemove={handleRemove}
          />
        )),
        containerRef.current,
      )}
    </ToastContext.Provider>
  );
}

export { ArvoToastProvider };
export default ArvoToastProvider;
